import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

interface ServiceConfig {
  service: string;
  label: string;
  fields: { key: string; label: string; value: string; secret: boolean }[];
  configured: boolean;
}

/** Admin settings — per-service credential config (GET/PATCH /api/admin/settings). */
@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
})
export class AdminSettingsComponent {
  loading = signal<boolean>(false);
  saved = signal<string>('');

  // Mock data — service_agent clears this and loads via ApiService.getAdminSettings().
  services = signal<ServiceConfig[]>([
    {
      service: 'postgresql',
      label: 'PostgreSQL database',
      configured: true,
      fields: [
        { key: 'POSTGRES_HOST', label: 'Host', value: 'db.internal', secret: false },
        { key: 'POSTGRES_USER', label: 'User', value: 'easyfile', secret: false },
        { key: 'POSTGRES_PASSWORD', label: 'Password', value: '••••••••', secret: true },
      ],
    },
    {
      service: 'minio',
      label: 'MinIO object storage',
      configured: false,
      fields: [
        { key: 'MINIO_ENDPOINT', label: 'Endpoint', value: '', secret: false },
        { key: 'MINIO_ACCESS_KEY', label: 'Access key', value: '', secret: false },
        { key: 'MINIO_SECRET_KEY', label: 'Secret key', value: '', secret: true },
      ],
    },
  ]);

  save(svc: ServiceConfig): void {
    // Mockup: service_agent will PATCH /api/admin/settings here.
    this.services.update((list) =>
      list.map((s) =>
        s.service === svc.service
          ? { ...s, configured: s.fields.every((f) => f.value.trim().length > 0) }
          : s,
      ),
    );
    this.saved.set(svc.service);
  }
}
